import 'package:task_manager_flutter/ui/widgets/generic_grid_screen.dart';
import 'package:flutter/material.dart';
import 'package:task_manager_flutter/data/utils/api_links.dart';
import 'package:task_manager_flutter/data/models/network_response.dart';
import 'package:task_manager_flutter/data/services/network_caller.dart';

class Diretorio {
  int? id;
  String nome;
  String descricao;

  Diretorio({
    this.id,
    required this.nome,
    required this.descricao,
  });

  factory Diretorio.fromJson(Map<String, dynamic> json) {
    return Diretorio(
      id: json['id'],
      nome: json['nome'],
      descricao: json['descricao'],
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'nome': nome,
      'descricao': descricao,
    };
  }

  static Future<List<Map<String, dynamic>>> loadCategorias() async {
    final NetworkResponse response = await NetworkCaller().getRequest(
      ApiLinks.getCategorias,
    );

    if (response.isSuccess && response.body != null) {
      final List<dynamic> data = response.body!['data']['account'] ?? [];
      return data
          .map(
            (item) => {
              'value': item['id'].toString(),
              'label': item['descricao'],
            },
          )
          .toList();
    }
    return [];
  }

  static List<FieldConfig> fieldConfigs = [
    FieldConfig(
      label: "Título",
      fieldName: "titulo",
      icon: Icons.title,
      isFilterable: true,
      isInForm: true,
      isRequired: true,
      validator: (value) {
        if (value == null || value.isEmpty) return 'Título é obrigatório';
        if (value.length < 3) return 'Título deve ter pelo menos 3 caracteres';
        return null;
      },
    ),
    FieldConfig(
      label: "Conteúdo",
      fieldName: "conteudo",
      icon: Icons.description,
      isFilterable: true,
      isInForm: true,
      maxLines: 3,
      fieldType: FieldType.multiline,
      isRequired: true,
    ),
    FieldConfig(
      label: "Categoria",
      fieldName: "setor",
      icon: Icons.category,
      isFilterable: true,
      isInForm: true,
      fieldType: FieldType.dropdown,
      dropdownFutureBuilder: () async {
        // Sua função que retorna um Future<List<Map<String, dynamic>>>
        return await loadCategorias();
      },
      dropdownValueField: 'id',
      dropdownDisplayField: 'descricao',
      isRequired: true,
    ),
    FieldConfig(
      label: "Autor",
      fieldName: "autor",
      icon: Icons.person,
      isFilterable: true,
      isInForm: true,
      isRequired: true,
    ),
  ];
}
